---- MODULE TwoPhaseCommit ----
EXTENDS Integers, Sequences, FiniteSets

CONSTANT N, FiniteSet

VARIABLES participants, coordinator, messages

TypeOK == /\ participants \in FiniteSet(N)
          /\ coordinator \in N
          /\ messages \in FiniteSet({[sender: N, receiver: N, type: {"Prepare", "VoteYes", "VoteNo", "Commit", "Abort"}, content: BOOLEAN}])

Init == /\ participants = {}
          /\ coordinator = 1
          /\ messages = {}

Next == \/ /\ coordinator \in N
          /\ participants' = participants \cup {coordinator}
          /\ messages' = messages \cup {[sender: coordinator, receiver: coordinator, type: "Prepare", content: TRUE]}
        \/ /\ coordinator \in N
          /\ participants' = participants
          /\ messages' = messages \cup {[sender: coordinator, receiver: p, type: "Prepare", content: TRUE] : p \in participants}
        \/ /\ p \in participants
          /\ messages' = messages \cup {[sender: p, receiver: coordinator, type: "VoteYes", content: TRUE] : p \in participants}
        \/ /\ p \in participants
          /\ messages' = messages \cup {[sender: p, receiver: coordinator, type: "VoteNo", content: FALSE] : p \in participants}
        \/ /\ coordinator \in N
          /\ messages' = messages \cup {[sender: coordinator, receiver: p, type: "Commit", content: TRUE] : p \in participants}
        \/ /\ coordinator \in N
          /\ messages' = messages \cup {[sender: coordinator, receiver: p, type: "Abort", content: FALSE] : p \in participants}

Spec == Init /\ [][Next]_<<participants, coordinator, messages>>

====
